向后端传多个参数

可以使用AJAX来根据表格id动态渲染表格。以下是一个示例代码：

```javascript
// 假设表格id为"tableId"
var tableId = "tableId";

// 使用AJAX发送请求获取表格数据
$.ajax({
  url: "your_api_endpoint", // 替换为实际的API接口地址
  type: "GET",
  data: { tableId: tableId },
  success: function(response) {
    // 成功获取表格数据后执行渲染操作
    var tableData = response.data; // 假设获取到的表格数据保存在response.data中

    // 渲染表格
    renderTable(tableData);
  },
  error: function(error) {
    // 请求失败处理
    console.log("请求失败", error);
  }
});

// 渲染表格的函数
function renderTable(data) {
  // 清空旧的表格内容
  $("#" + tableId).empty();

  // 根据数据生成新的表格内容
  for (var i = 0; i < data.length; i++) {
    var row = $("<tr>");

    var cell1 = $("<td>").text(data[i].column1);
    var cell2 = $("<td>").text(data[i].column2);
    // ... 创建其他单元格，根据实际数据列数进行调整

    row.append(cell1, cell2); // 添加单元格到行中

    $("#" + tableId).append(row); // 添加行到表格中
  }
}
```

在示例中，我们使用了`$.ajax()`函数来发送GET请求获取表格数据，并根据获取到的数据动态生成表格内容。可以根据实际情况调整代码中的API接口地址、数据处理逻辑和表格渲染方式。

